package main

import (
	"bufio"
	"fmt"
	"os"
	"strconv"
	"strings"
)

func tostr(vet []int) string {
	res := "["
    for i, v := range vet {
        res += strconv.Itoa(v) // Converte int para string
        if i < len(vet)-1 {
            res += ", " // Adiciona espaço entre os números, mas não no último
        }
    }

    res+= "]"
	return res
}

func tostrrev(vet []int) string {
	if len(vet) == 0{
		return "[]"
	}
	aux := make([]int, len(vet))
	copy(aux, vet)
	reverse(aux)
	return tostr(aux)
}

// reverse: inverte os elementos do slice
func reverse(vet []int) {

	if len(vet) <= 1 {
		return
	}
	ult := len(vet) - 1
	vet[0], vet[ult] = vet[ult], vet[0]
	reverse(vet[1:ult])


}

// sum: soma dos elementos do slice
func sum(vet []int) int {
	if len(vet) == 0 {
		return 0
	}
	return vet[0] + sum(vet[1:])
}

// mult: produto dos elementos do slice
func mult(vet []int) int {
	if len(vet)== 0{
		return 1
	}
	return vet[0] * mult(vet[1:])
}

// min: retorna o índice e valor do menor valor
// crie uma função recursiva interna do modelo
// var rec func(v []int) (int, int)
// para fazer uma recursão que retorna valor e índice
func min(vet []int) int {

    if len(vet) == 0{
        return -1
    }
	if len(vet)== 1 {
		return 0
	}

    idx := min(vet[1:]) + 1

    if vet[0] <= vet[idx] {
        return 0
    }

    return idx
}

func main() {
	var vet []int
	scanner := bufio.NewScanner(os.Stdin)
	for {
		if !scanner.Scan() {
			break
		}
		line := scanner.Text()
		args := strings.Fields(line)
		fmt.Println("$" + line)

		switch args[0] {
		case "end":
			return
		case "read":
			vet = nil
			for _, arg := range args[1:] {
				if val, err := strconv.Atoi(arg); err == nil {
					vet = append(vet, val)
				}
			}
		case "tostr":
			fmt.Println(tostr(vet))
		case "torev":
			fmt.Println(tostrrev(vet))
		case "reverse":
			reverse(vet)
		case "sum":
			fmt.Println(sum(vet))
		case "mult":
			fmt.Println(mult(vet))
		case "min":
			fmt.Println(min(vet))
		default:
			fmt.Println("fail: comando invalido")
		}
	}
}
